package agent

import (
	"encoding/json"
	"fmt"
	"strings"
)

// Session log JSONL schema reference.
//
// The agent harness writes one event per line to .ddx/agent-logs/agent-*.jsonl
// (or to the per-run SessionLogDir override). Every line has the envelope:
//
//	{"session_id": string, "seq": int, "type": string, "ts": RFC3339Nano, "data": {...}}
//
// Two schema modes coexist. Lean mode is always on by default and is what
// existing tooling consumes. Verbose mode is opt-in via the env var
// DDX_LOG_VERBOSE=1; when set, the writer adds extra fields to a
// few event types so a session can be replayed and root-caused without
// loss of inputs and outputs. Lean fields are never removed in verbose
// mode — verbose is strictly additive (with the single exception that
// tool.call events are deferred until the matching tool_result arrives,
// so they can include output/duration_ms/error in one line).
//
// Per-event-type fields:
//
//	session.start (lean and verbose):
//	  data.model       string  — model id reported by the harness
//	  data.session_id  string  — session id from the harness CLI
//	  data.bead_id     string  — bead under which the session ran (may be "")
//	  data.elapsed_ms  int     — ms since session start (always 0 here)
//	  data.harness     string  — "claude" | "fiz" | etc.
//
//	llm.request (lean and verbose):
//	  data.attempt_index int        — request attempt counter (0-based)
//	  data.messages      []object   — conversation messages (last user message hint used by the renderer)
//
//	llm.response (lean):
//	  data.model         string  — resolved model id
//	  data.latency_ms    int     — per-call wall time (request → response)
//	  data.tool_calls    []{name} — tool_use names emitted in this turn
//	  data.turn          int     — 1-based assistant turn count
//	  data.bead_id       string
//	  data.elapsed_ms    int     — ms since session start
//	  data.input_tokens  int     — running input tokens (latest seen)
//	  data.output_tokens int     — running output tokens (latest seen)
//	  data.attempt.cost.raw.total_tokens int — running total
//
//	llm.response (verbose adds):
//	  data.content       string  — concatenated assistant text blocks for this turn
//	  data.finish_reason string  — claude stop_reason ("end_turn", "tool_use", "max_tokens", ...)
//	  data.usage object:
//	    input_tokens                int
//	    output_tokens               int
//	    cache_creation_input_tokens int
//	    cache_read_input_tokens     int
//	    total_tokens                int
//
//	tool.call (lean):
//	  data.tool       string         — tool name
//	  data.input      object         — tool arguments as decoded JSON
//	  data.bead_id    string
//	  data.elapsed_ms int            — ms since session start
//	  data.turn       int            — assistant turn that issued the call
//
//	tool.call (verbose) — emitted when the matching tool_result arrives so output is populated:
//	  data.tool        string
//	  data.input       object
//	  data.output      string  — tool_result content (joined if structured)
//	  data.duration_ms int     — wall time from tool_use → tool_result
//	  data.error       string  — non-empty when tool_result is_error=true; empty otherwise
//	  data.bead_id     string
//	  data.elapsed_ms  int     — ms-from-session-start at the time of the originating tool_use
//	  data.turn        int     — assistant turn that issued the call
//
// Verbose mode is off by default; existing consumers of the lean schema
// (TailSessionLogs, FormatSessionLogLines, the server worker log endpoint)
// keep working unchanged because they tolerate extra fields.

// FormatSessionLogLines formats Fizeau-style JSONL log entries into readable progress.
// It is used by both the CLI (local execute-loop) and the server worker log endpoint.
func FormatSessionLogLines(lines []string) string {
	var sb strings.Builder
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry map[string]any
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			continue
		}
		entryType, _ := entry["type"].(string)
		switch entryType {
		case "session.start":
			model, _ := entry["data"].(map[string]any)["model"].(string)
			fmt.Fprintf(&sb, "▶ session started (model: %s)\n", model)
		case "llm.request":
			data, _ := entry["data"].(map[string]any)
			attemptIdx, _ := data["attempt_index"].(float64)
			// Extract a hint from the last user message in the conversation.
			promptHint := ""
			if msgs, ok := data["messages"].([]any); ok {
				for i := len(msgs) - 1; i >= 0; i-- {
					if msg, ok := msgs[i].(map[string]any); ok {
						if role, _ := msg["role"].(string); role == "user" {
							if content, _ := msg["content"].(string); content != "" {
								promptHint = " [" + truncateStr(strings.TrimSpace(content), 60) + "]"
							}
							break
						}
					}
				}
			}
			fmt.Fprintf(&sb, "  → llm request (attempt %.0f)%s\n", attemptIdx, promptHint)
		case "llm.response":
			data, _ := entry["data"].(map[string]any)
			model, _ := data["model"].(string)
			latency, _ := data["latency_ms"].(float64)
			// Tokens: data.attempt.cost.raw.total_tokens
			var tokens float64
			if attempt, ok := data["attempt"].(map[string]any); ok {
				if cost, ok := attempt["cost"].(map[string]any); ok {
					if raw, ok := cost["raw"].(map[string]any); ok {
						tokens, _ = raw["total_tokens"].(float64)
					}
				}
			}
			// Tool calls from response
			toolCalls, _ := data["tool_calls"].([]any)
			finishReason, _ := data["finish_reason"].(string)
			suffix := ""
			if len(toolCalls) > 0 {
				var names []string
				for _, tc := range toolCalls {
					if tcm, ok := tc.(map[string]any); ok {
						n, _ := tcm["name"].(string)
						if n != "" {
							names = append(names, n)
						}
					}
				}
				suffix = fmt.Sprintf(" → %s", strings.Join(names, ", "))
			} else if finishReason != "" {
				suffix = fmt.Sprintf(" (%s)", finishReason)
			}
			fmt.Fprintf(&sb, "  ← llm response (%.0f tokens, %.1fs) %s%s\n", tokens, latency/1000, model, suffix)
		case "llm.delta":
			// Skip deltas — too verbose for summary
		case "progress":
			if line := formatProgressLogEntry(entry); line != "" {
				fmt.Fprint(&sb, line)
			}
		case "tool.call":
			data, _ := entry["data"].(map[string]any)
			name, _ := data["tool"].(string)
			inp, _ := data["input"].(map[string]any)
			dur, _ := data["duration_ms"].(float64)
			argHint := ""
			if len(inp) > 0 {
				// Prefer path/command/query keys for display
				for _, key := range []string{"path", "command", "query", "file"} {
					if v, ok := inp[key]; ok {
						argHint = truncateStr(fmt.Sprintf("%v", v), 60)
						break
					}
				}
				if argHint == "" {
					for _, v := range inp {
						argHint = truncateStr(fmt.Sprintf("%v", v), 60)
						break
					}
				}
			}
			errMsg, _ := data["error"].(string)
			errSuffix := ""
			if errMsg != "" {
				errSuffix = fmt.Sprintf(" ❌ %s", truncateStr(errMsg, 40))
			}
			durSuffix := ""
			if dur > 0 {
				durSuffix = fmt.Sprintf(" (%.1fs)", dur/1000)
			}
			fmt.Fprintf(&sb, "  🔧 %s %s%s%s\n", name, argHint, durSuffix, errSuffix)
		case "bead.claimed":
			data, _ := entry["data"].(map[string]any)
			beadID, _ := data["bead_id"].(string)
			title, _ := data["title"].(string)
			if title != "" {
				fmt.Fprintf(&sb, "\n▶ %s: %s\n", beadID, title)
			} else {
				fmt.Fprintf(&sb, "\n▶ %s\n", beadID)
			}
		case "bead.result":
			data, _ := entry["data"].(map[string]any)
			beadID, _ := data["bead_id"].(string)
			status, _ := data["status"].(string)
			detail, _ := data["detail"].(string)
			resultRev, _ := data["result_rev"].(string)
			preserveRef, _ := data["preserve_ref"].(string)
			rationale, _ := data["no_changes_rationale"].(string)
			durationMs, _ := data["duration_ms"].(float64)
			var outcome string
			switch status {
			case "success":
				shortRev := resultRev
				if len(shortRev) > 8 {
					shortRev = shortRev[:8]
				}
				if shortRev != "" {
					outcome = fmt.Sprintf("merged (%s)", shortRev)
				} else {
					outcome = "merged"
				}
			case "already_satisfied", "no_changes":
				outcome = status
			default:
				if detail == "" {
					detail = status
				}
				if preserveRef != "" {
					outcome = fmt.Sprintf("preserved: %s", detail)
				} else {
					outcome = fmt.Sprintf("error: %s", detail)
				}
			}
			durStr := ""
			if durationMs > 0 {
				durStr = fmt.Sprintf(" (%.1fs)", durationMs/1000)
			}
			fmt.Fprintf(&sb, "✓ %s → %s%s\n", beadID, outcome, durStr)
			if rationale != "" {
				fmt.Fprintf(&sb, "  rationale: %s\n", rationale)
			}
		case "loop.end":
			data, _ := entry["data"].(map[string]any)
			attempts, _ := data["attempts"].(float64)
			successes, _ := data["successes"].(float64)
			failures, _ := data["failures"].(float64)
			if attempts > 0 {
				fmt.Fprintf(&sb, "\nloop done: %.0f attempted, %.0f succeeded, %.0f failed\n", attempts, successes, failures)
			}
		case "compaction.start":
			// Suppress: we'll show a single line on compaction.end only if it succeeded.
		case "compaction.end":
			data, _ := entry["data"].(map[string]any)
			success, _ := data["success"].(bool)
			if success {
				tokensBefore, _ := data["tokens_before"].(float64)
				tokensAfter, _ := data["tokens_after"].(float64)
				if tokensBefore > 0 && tokensAfter > 0 {
					fmt.Fprintf(&sb, "  ⚡ compacted context (%.0f → %.0f tokens)\n", tokensBefore, tokensAfter)
				} else {
					fmt.Fprintf(&sb, "  ⚡ compacted context\n")
				}
			}
		}
	}
	return sb.String()
}

func truncateStr(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen-1] + "…"
}

func formatProgressLogEntry(entry map[string]any) string {
	data, _ := entry["data"].(map[string]any)
	message, _ := data["message"].(string)

	if message != "" {
		return fmt.Sprintf("  %s\n", truncateStr(message, 120))
	}
	return ""
}

package agent

import (
	"bufio"
	"context"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"
)

type fileTrackState struct {
	offset int64
}

type sessionLogFile struct {
	path string
}

// TailSessionLogs watches the agent log directory for new/modified session log
// files and writes formatted progress to dst. It stops when ctx is cancelled.
// Callers should run this in a goroutine while ExecuteBead runs synchronously.
func TailSessionLogs(ctx context.Context, projectRoot string, dst io.Writer) {
	logDir := filepath.Join(projectRoot, DefaultLogDir)
	states := make(map[string]*fileTrackState)

	// Record existing files so we don't replay old logs
	for _, file := range listSessionLogFiles(projectRoot, logDir) {
		if info, err := os.Stat(file.path); err == nil {
			states[file.path] = &fileTrackState{offset: info.Size()}
		}
	}

	ticker := time.NewTicker(500 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			readNewLogLines(projectRoot, logDir, states, dst)
			return
		case <-ticker.C:
			readNewLogLines(projectRoot, logDir, states, dst)
		}
	}
}

// readNewLogLines reads any new lines from agent session logs and formats them.
func readNewLogLines(projectRoot, logDir string, states map[string]*fileTrackState, dst io.Writer) {
	for _, file := range listSessionLogFiles(projectRoot, logDir) {
		path := file.path
		st, err := os.Stat(path)
		if err != nil {
			continue
		}

		fs, ok := states[path]
		if !ok {
			fs = &fileTrackState{}
			states[path] = fs
		}

		if st.Size() <= fs.offset {
			continue
		}

		f, err := os.Open(path)
		if err != nil {
			continue
		}

		_, _ = f.Seek(fs.offset, io.SeekStart)
		scanner := bufio.NewScanner(f)
		// 16MB max line. Session-log `response` fields observed up to ~7MB in
		// real incidents (2026-04-20 reviewer-malfunction report). Matches bead
		// store and claude stream for consistency.
		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
		var newLines []string
		for scanner.Scan() {
			line := scanner.Text()
			if strings.TrimSpace(line) != "" {
				newLines = append(newLines, line)
			}
		}
		fs.offset, _ = f.Seek(0, io.SeekCurrent)
		f.Close()

		if len(newLines) > 0 {
			formatted := FormatSessionLogLines(newLines)
			if formatted != "" {
				fmt.Fprint(dst, formatted)
			}
		}
	}
}

func listSessionLogFiles(projectRoot, logDir string) []sessionLogFile {
	var files []sessionLogFile
	appendDirLogs := func(dir string) {
		entries, err := os.ReadDir(dir)
		if err != nil {
			return
		}
		for _, entry := range entries {
			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".jsonl") {
				continue
			}
			name := entry.Name()
			if strings.HasPrefix(name, "agent-loop-") {
				continue
			}
			if strings.HasPrefix(name, "agent-") || strings.HasPrefix(name, "svc-") {
				files = append(files, sessionLogFile{path: filepath.Join(dir, name)})
			}
		}
	}

	appendDirLogs(logDir)
	embeddedDirs, _ := filepath.Glob(filepath.Join(projectRoot, ".ddx", "executions", "*", "embedded"))
	for _, dir := range embeddedDirs {
		appendDirLogs(dir)
	}
	return files
}

// a deprecated no-op and the server-submit path is removed from this CLI
// surface — server-spawned workers exec `ddx work` directly.

// Pre-flight: validate harness availability and model compatibility
// before claiming any beads. This surfaces errors like "claude binary
// not found" or "vidar is an agent preset, not a claude model" before
// any bead status changes hands.
// Skipped for ddx work (treatPassthroughAsOpaque=true): harness/provider/model
// are opaque passthrough constraints there; DDx does not validate them.
if !treatPassthroughAsOpaque {
	if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, harness, model, provider, modelRef); err != nil {
		return fmt.Errorf("execute-loop: %w", err)
	}
}

store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))

// Structured progress sink for this loop run. Events emitted at
// loop.start, bead.claimed, bead.result, and loop.end land here so
// log aggregators (FormatSessionLogLines, `ddx server workers log`)
// can parse the same JSONL envelope used by harness session logs.
loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
_ = os.MkdirAll(loopLogDir, 0o755)
loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
var loopSink io.Writer
if f, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
	loopSink = f
	defer f.Close() //nolint:errcheck
}

// ADR-022 step 2: spin up the worker server-probe + best-effort event
// mirror. The probe is autonomous-friendly: if no ddx-server is
// reachable, it buffers events into a 200-cap ring; on
// NotConnected→Connected transitions it registers and flushes the
// backfill. Per ADR-022 the worker keeps working regardless of probe
// state, so this code never blocks the loop on network I/O.
probeIdent := workerprobe.Identity{
	ProjectRoot:  projectRoot,
	Harness:      harness,
	Model:        model,
	ExecutorPID:  os.Getpid(),
	ExecutorHost: hostnameOrEmpty(),
	StartedAt:    time.Now().UTC(),
}
probe := workerprobe.New(probeIdent, workerprobe.Config{
	AddrFunc: serverpkg.ReadServerAddr,
})
probeCtx, probeCancel := context.WithCancel(context.Background())
probe.Start(probeCtx)
defer func() {
	probeCancel()
	probe.Stop()
}()
if loopSink != nil {
	loopSink = workerprobe.TeeJSONL(loopSink, probe)
} else {
	loopSink = workerprobe.TeeJSONL(io.Discard, probe)
}

// Start session log tailer so the user sees progress during agent execution
tailCtx, tailCancel := context.WithCancel(context.Background())
go agent.TailSessionLogs(tailCtx, projectRoot, cmd.OutOrStdout())

// Instantiate a process-local LandCoordinator for the inline land path.
// Stopped on function exit.
localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
defer localCoord.Stop()

// Build post-merge reviewer unless --no-review is set.
// Reviewer is on-by-default: runs at smart tier after every successful merge.
var reviewer agent.BeadReviewer
if !noReview {
	reviewer = &agent.DefaultBeadReviewer{
		ProjectRoot: projectRoot,
		BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
		BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
		Harness:     reviewHarness,
		Model:       reviewModel,
	}
}

profile = agent.NormalizeRoutingProfile(profile)

// Cost-cap state shared across attempts for this loop run.
// paths. Accumulated billed spend (excluding local and subscription
// providers) above --max-cost trips the cap and halts further bead
// claiming. See escalation.DefaultMaxCostUSD / CountsTowardCostCap.
costCap := escalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
	// Resolve the harness's billing class via the service. Treat any
	// resolution error as "count by default" (safe — we'd rather cap
	// early than silently overshoot).
	svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
	if svcErr != nil {
		return true
	}
	infos, err := svc.ListHarnesses(context.Background())
	if err != nil {
		return true
	}
	for _, h := range infos {
		if h.Name == harnessName {
			return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
		}
	}
	return true
})
accumulateBilledCost := func(report agent.ExecuteBeadReport) {
	costCap.Add(report.Harness, report.CostUSD)
}
costCapTripped := func() (agent.ExecuteBeadReport, bool) {
	detail, tripped := costCap.Tripped()
	if !tripped {
		return agent.ExecuteBeadReport{}, false
	}
	return agent.ExecuteBeadReport{

package agent

import (
	"encoding/json"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestFormatSessionLogLines_RendersFizeauProgressEvents(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":   "thinking",
			"state":   "start",
			"message": "ddx-99419bc1 #1 thinking ...",
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":         "thinking",
			"state":         "complete",
			"message":       "ddx-99419bc1 #1 thought 5.0s",
			"output_tokens": 8,
			"duration_ms":   5000,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":       "tool",
			"state":       "start",
			"message":     "ddx-99419bc1 #1 tool `ls -al` start",
			"tool_name":   "shell",
			"command":     "ls -al",
			"duration_ms": 0,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":        "tool",
			"state":        "complete",
			"message":      "ddx-99419bc1 #1 tool `ls -al` done 3.0s",
			"command":      "ls -al",
			"duration_ms":  3000,
			"total_tokens": 100,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":        "response",
			"state":        "complete",
			"message":      "ddx-99419bc1 #1 done 100tok",
			"total_tokens": 100,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":           "context",
			"state":           "update",
			"message":         "ddx-99419bc1 #1 context edited routing output and verified tests",
			"session_summary": "edited routing output and verified tests",
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  ddx-99419bc1 #1 thinking ...\n")
	assert.Contains(t, got, "  ddx-99419bc1 #1 thought 5.0s\n")
	assert.Contains(t, got, "  ddx-99419bc1 #1 tool `ls -al` start\n")
	assert.Contains(t, got, "  ddx-99419bc1 #1 tool `ls -al` done 3.0s\n")
	assert.Contains(t, got, "  ddx-99419bc1 #1 done 100tok\n")
	assert.Contains(t, got, "  ddx-99419bc1 #1 context edited routing output and verified tests\n")
	assert.NotContains(t, got, "running tool call")
}

func mustSessionLogLine(t *testing.T, typ string, data map[string]any) string {
	t.Helper()
	body, err := json.Marshal(map[string]any{
		"type": typ,
		"data": data,
	})
	require.NoError(t, err)
	return string(body)
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// Public event-type strings emitted by agentlib.FizeauService.Execute, mirrored
// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
// drain loop does not have to import the agent's internal/harnesses
// package (which is module-private).
const (
	serviceEventRoutingDecision = "routing_decision"
	serviceEventProgress        = "progress"
	serviceEventTextDelta       = "text_delta"
	serviceEventToolCall        = "tool_call"
	serviceEventToolResult      = "tool_result"
	serviceEventStall           = "stall"
	serviceEventFinal           = "final"
	serviceEventCompaction      = "compaction"
	serviceEventCompactionEnd   = "compaction.end"
)

const (
	serviceNoopCompactionWallClockLimit  = 15 * time.Minute
	serviceNoopCompactionWallClockReason = "compaction_stuck_wall_clock_timeout"
)

// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
// copies of these structs because CONTRACT-003 hadn't published them; that
// left the consumer carrying stream-adjacent knowledge and drifted whenever
// upstream shapes changed. With v0.8.0 the types are public and stable.
//
// Aliases rather than an outright delete so existing call sites keep
// working without a sweep. New code can (and should) use agentlib types
// directly.
type (
	serviceFinalData      = agentlib.ServiceFinalData
	serviceFinalUsage     = agentlib.ServiceFinalUsage
	serviceToolCallData   = agentlib.ServiceToolCallData
	serviceToolResultData = agentlib.ServiceToolResultData
)

type serviceRoutingActual struct {
	Harness                     string
	Provider                    string
	Model                       string
	PredictedPower              int
	PredictedSpeedTPS           float64
	PredictedCostUSDPer1kTokens float64
	PredictedCostSource         string
}

// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.FizeauService.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.FizeauService.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
// stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   logDir,
		Metadata:        opts.Correlation,
	}

	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()

	start := time.Now()
	events, err := svc.Execute(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, toolCalls, routing, actualPower := drainServiceEvents(events)
	elapsed := time.Since(start)

	result := &Result{
		Harness:    "agent",
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
		ToolCalls:  toolCalls,
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int so the API can distinguish
			// "harness reported zero" from "harness didn't report". Treat
			// nil as zero for DDx's int-valued result struct.
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		switch final.Status {
		case "success", "":
			// happy path; no-op
		case "stalled":
			result.ExitCode = 1
			if final.Error != "" {
				result.Error = "stalled: " + final.Error
			} else {
				result.Error = "stalled"
			}
		case "timed_out":
			result.ExitCode = 1
			result.Error = fmt.Sprintf("timeout after %v", wallClock.Round(time.Second))
		case "cancelled":
			result.ExitCode = 1
			result.Error = "cancelled"
		default:
			result.ExitCode = 1
			if final.Error != "" {
				result.Error = final.Error
			} else {
				result.Error = final.Status
			}
		}
		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)

