// TestParseClaudeStream feeds synthetic stream-json events through the
// parser and asserts:
//
//  1. Progress lines (session.start, llm.response, tool.call) are emitted
//     for relevant events so the existing TailSessionLogs pipeline can
//     render them.
//  2. The final aggregated result captures the text, tokens, cost, and
//     session id from the authoritative "result" event.
//  3. The parser stays lenient in the face of garbage lines.
//
// The table-driven form exercises multiple event shapes so regressions in
// one case don't hide breakage in another.
func TestParseClaudeStream(t *testing.T) {
	cases := []struct {
		name              string
		input             string
		wantTurnCount     int
		wantToolCalls     int
		wantInputTokens   int
		wantOutputTokens  int
		wantCostUSD       float64
		wantFinalText     string
		wantSessionID     string
		wantModel         string
		wantProgressTypes []string
	}{
		{
			name: "full stream with tool use and result",
			input: strings.Join([]string{
				`{"type":"system","subtype":"init","session_id":"sess-abc","model":"claude-sonnet-4-6","tools":["Bash","Read"]}`,
				`{"type":"assistant","message":{"id":"m-1","model":"claude-sonnet-4-6","content":[{"type":"text","text":"Starting"},{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":120,"output_tokens":42}}}`,
				`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"README.md\nfoo.go"}]}}`,
				`{"type":"assistant","message":{"id":"m-2","model":"claude-sonnet-4-6","content":[{"type":"text","text":"Done."}],"usage":{"input_tokens":260,"output_tokens":88}}}`,
				`{"type":"result","subtype":"success","is_error":false,"duration_ms":1200,"result":"All done.","usage":{"input_tokens":260,"output_tokens":88},"total_cost_usd":0.0123,"session_id":"sess-abc"}`,
			}, "\n"),
			wantTurnCount:     2,
			wantToolCalls:     1,
			wantInputTokens:   260,
			wantOutputTokens:  88,
			wantCostUSD:       0.0123,
			wantFinalText:     "All done.",
			wantSessionID:     "sess-abc",
			wantModel:         "claude-sonnet-4-6",
			wantProgressTypes: []string{"session.start", "llm.response", "tool.call", "llm.response"},
		},
		{
			name: "garbage lines are skipped",
			input: strings.Join([]string{
				`not json`,
				`{"type":"system","subtype":"init","session_id":"sess-xyz","model":"claude-sonnet-4-6"}`,
				`{garbage`,
				`{"type":"assistant","message":{"content":[{"type":"tool_use","id":"tu-2","name":"Read","input":{"path":"/tmp/x"}}],"usage":{"input_tokens":10,"output_tokens":5}}}`,
				`{"type":"result","subtype":"success","result":"ok","usage":{"input_tokens":10,"output_tokens":5},"total_cost_usd":0.001,"session_id":"sess-xyz"}`,
			}, "\n"),
			wantTurnCount:     1,
			wantToolCalls:     1,
			wantInputTokens:   10,
			wantOutputTokens:  5,
			wantCostUSD:       0.001,
			wantFinalText:     "ok",
			wantSessionID:     "sess-xyz",
			wantModel:         "claude-sonnet-4-6",
			wantProgressTypes: []string{"session.start", "llm.response", "tool.call"},
		},
		{
			name: "text-only assistant without tool_use still emits progress",
			input: strings.Join([]string{
				`{"type":"system","subtype":"init","session_id":"sess-t","model":"claude-sonnet-4-6"}`,
				`{"type":"assistant","message":{"content":[{"type":"text","text":"hello"}],"usage":{"input_tokens":3,"output_tokens":2}}}`,
				`{"type":"result","subtype":"success","result":"hello","usage":{"input_tokens":3,"output_tokens":2},"total_cost_usd":0.0001,"session_id":"sess-t"}`,
			}, "\n"),
			wantTurnCount:     1,
			wantToolCalls:     0,
			wantInputTokens:   3,
			wantOutputTokens:  2,
			wantCostUSD:       0.0001,
			wantFinalText:     "hello",
			wantSessionID:     "sess-t",
			wantModel:         "claude-sonnet-4-6",
			wantProgressTypes: []string{"session.start", "llm.response"},
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			var progressBuf bytes.Buffer
			start := time.Now().Add(-3 * time.Second) // exercise elapsed_ms > 0
			res, err := parseClaudeStream(strings.NewReader(tc.input), &progressBuf, "sess-test", "ddx-12345678", start)
			require.NoError(t, err)
			require.NotNil(t, res)

			assert.Equal(t, tc.wantTurnCount, res.TurnCount, "turn count")
			assert.Equal(t, tc.wantToolCalls, res.ToolCalls, "tool call count")
			assert.Equal(t, tc.wantInputTokens, res.InputTokens, "input tokens")
			assert.Equal(t, tc.wantOutputTokens, res.OutputTokens, "output tokens")
			assert.InDelta(t, tc.wantCostUSD, res.CostUSD, 1e-9, "cost usd")
			assert.Equal(t, tc.wantFinalText, res.FinalText, "final text")
			assert.Equal(t, tc.wantSessionID, res.SessionID, "session id")
			assert.Equal(t, tc.wantModel, res.Model, "model")
			assert.False(t, res.IsError)

			// Walk the emitted progress lines and confirm the expected types
			// appear in order.
			var gotTypes []string
			for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
				if line == "" {
					continue
				}
				var entry map[string]any
				require.NoError(t, json.Unmarshal([]byte(line), &entry), "progress line must be valid JSON: %s", line)
				t, _ := entry["type"].(string)
				gotTypes = append(gotTypes, t)
			}
			assert.Equal(t, tc.wantProgressTypes, gotTypes, "progress event types (in order)")

			// Spot-check that at least one tool.call line carries the bead_id
			// so execute-bead operators can grep the log stream.
			if tc.wantToolCalls > 0 {
				assert.Contains(t, progressBuf.String(), `"bead_id":"ddx-12345678"`)
				assert.Contains(t, progressBuf.String(), `"tool.call"`)
			}
		})
	}
}

// TestParseClaudeStreamVerboseMode asserts that with DDX_LOG_VERBOSE=1
// the parser produces enriched llm.response events (content, finish_reason,
// full usage object including cache fields) and emits tool.call events
// only after the matching tool_result, with input, output, duration_ms,
// and error all populated.
func TestParseClaudeStreamVerboseMode(t *testing.T) {
	t.Setenv("DDX_LOG_VERBOSE", "1")
	input := strings.Join([]string{
		`{"type":"system","subtype":"init","session_id":"sess-v","model":"claude-sonnet-4-6"}`,
		`{"type":"assistant","message":{"id":"m-1","model":"claude-sonnet-4-6","stop_reason":"tool_use","content":[{"type":"text","text":"running ls"},{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":120,"output_tokens":42,"cache_creation_input_tokens":10,"cache_read_input_tokens":80}}}`,
		`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"README.md\nfoo.go","is_error":false}]}}`,
		`{"type":"assistant","message":{"id":"m-2","model":"claude-sonnet-4-6","stop_reason":"end_turn","content":[{"type":"text","text":"All done."}],"usage":{"input_tokens":260,"output_tokens":88,"cache_creation_input_tokens":0,"cache_read_input_tokens":200}}}`,
		`{"type":"result","subtype":"success","is_error":false,"duration_ms":1200,"result":"All done.","usage":{"input_tokens":260,"output_tokens":88},"total_cost_usd":0.0123,"session_id":"sess-v"}`,
	}, "\n")

	var progressBuf bytes.Buffer
	res, err := parseClaudeStream(strings.NewReader(input), &progressBuf, "sess-v", "ddx-verbose", time.Now())
	require.NoError(t, err)
	require.NotNil(t, res)

	type envelope struct {
		Type string                 `json:"type"`
		Data map[string]interface{} `json:"data"`
	}
	var llmResponses []map[string]interface{}
	var toolCalls []map[string]interface{}
	for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
		if line == "" {
			continue
		}
		var env envelope
		require.NoError(t, json.Unmarshal([]byte(line), &env))
		switch env.Type {
		case "llm.response":
			llmResponses = append(llmResponses, env.Data)
		case "tool.call":
			toolCalls = append(toolCalls, env.Data)
		}
	}
	require.Len(t, llmResponses, 2, "expected two llm.response events")
	require.Len(t, toolCalls, 1, "expected one tool.call event (deferred until tool_result)")

	// llm.response[0] — assistant turn that issued a tool_use.
	first := llmResponses[0]
	assert.Equal(t, "running ls", first["content"], "verbose llm.response must include content")
	assert.Equal(t, "tool_use", first["finish_reason"], "verbose llm.response must include finish_reason")
	usage, ok := first["usage"].(map[string]interface{})
	require.True(t, ok, "verbose llm.response must include usage object")
	assert.EqualValues(t, 120, usage["input_tokens"])
	assert.EqualValues(t, 42, usage["output_tokens"])
	assert.EqualValues(t, 10, usage["cache_creation_input_tokens"])
	assert.EqualValues(t, 80, usage["cache_read_input_tokens"])
	assert.EqualValues(t, 162, usage["total_tokens"])

	// llm.response[1] — final text turn.
	second := llmResponses[1]
	assert.Equal(t, "All done.", second["content"])
	assert.Equal(t, "end_turn", second["finish_reason"])

	// tool.call — verbose deferred event with output/duration/error populated.
	tc := toolCalls[0]
	assert.Equal(t, "Bash", tc["tool"])
	input2, ok := tc["input"].(map[string]interface{})
	require.True(t, ok, "verbose tool.call must include decoded input")
	assert.Equal(t, "ls", input2["command"])
	assert.Equal(t, "README.md\nfoo.go", tc["output"], "verbose tool.call must include tool_result output")
	_, hasDuration := tc["duration_ms"]
	assert.True(t, hasDuration, "verbose tool.call must include duration_ms")
	assert.Equal(t, "", tc["error"], "verbose tool.call must include error field (empty on success)")
	assert.Equal(t, "ddx-verbose", tc["bead_id"])
	assert.EqualValues(t, 1, tc["turn"])
}

// TestParseClaudeStreamVerboseLeanDefault asserts that the lean schema is
// the default — when DDX_LOG_VERBOSE is unset, llm.response events

// drainServiceEvents reads service events and returns the final-event payload,
// the accumulated tool-call log, the routing decision (when present in the
// routing_decision start event), and the power of the selected model (0 when
// the routing_decision event does not include candidate power components).
// A sustained run of no-op compaction telemetry is converted into a synthetic
// stalled final so execute-bead result details identify the time-based
// breaker instead of waiting for the outer wall clock.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, []ToolCallEntry, *serviceRoutingActual, int) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var toolCalls []ToolCallEntry
	pending := make(map[string]*ToolCallEntry) // call_id -> entry awaiting result
	var noopCompactions serviceNoopCompactionStreak
	var noopTimer *time.Timer
	var noopTimerC <-chan time.Time
	defer func() { stopNoopCompactionTimer(noopTimer) }()

	for {
		select {
		case <-noopTimerC:
			detail := noopCompactions.detail(serviceNoopCompactionWallClockLimit, serviceNoopCompactionWallClockLimit)
			return &serviceFinalData{
				Status: "stalled",
				Error:  detail,
			}, toolCallsWithPending(toolCalls, pending), routing, routingPower
		case ev, ok := <-events:
			if !ok {
				// Any tool_call without a matching tool_result still gets recorded.
				return final, toolCallsWithPending(toolCalls, pending), routing, routingPower
			}
			if isNoopCompactionEvent(ev) {
				detail, started := noopCompactions.record(eventTimestamp(ev), serviceNoopCompactionWallClockLimit)
				if started {
					noopTimer, noopTimerC = resetNoopCompactionTimer(noopTimer, serviceNoopCompactionWallClockLimit)
				}
				if detail != "" {
					return &serviceFinalData{
						Status: "stalled",
						Error:  detail,
					}, toolCallsWithPending(toolCalls, pending), routing, routingPower
				}
				continue
			}
			if isServiceProgressEvent(ev) {
				noopCompactions.reset()
				stopNoopCompactionTimer(noopTimer)
				noopTimerC = nil
			}

			switch string(ev.Type) {
			case serviceEventRoutingDecision:
				var payload struct {
					Harness    string `json:"harness"`
					Provider   string `json:"provider"`
					Model      string `json:"model"`
					Candidates []struct {
						Model              string  `json:"model"`
						Eligible           bool    `json:"eligible"`
						CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
						CostSource         string  `json:"cost_source"`
						Components         struct {
							Power    int     `json:"power"`
							SpeedTPS float64 `json:"speed_tps"`
						} `json:"components"`
					} `json:"candidates"`
				}
				if err := json.Unmarshal(ev.Data, &payload); err == nil {
					routing = &serviceRoutingActual{
						Harness:  payload.Harness,
						Provider: payload.Provider,
						Model:    payload.Model,
					}
					for _, c := range payload.Candidates {
						if c.Eligible && c.Model == payload.Model {
							routingPower = c.Components.Power
							routing.PredictedPower = c.Components.Power
							routing.PredictedSpeedTPS = c.Components.SpeedTPS
							routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
							routing.PredictedCostSource = c.CostSource
							break
						}
					}
				}
			case serviceEventToolCall:
				var data serviceToolCallData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					entry := &ToolCallEntry{
						Tool:  data.Name,
						Input: string(data.Input),
					}
					pending[data.ID] = entry
				}
			case serviceEventToolResult:
				var data serviceToolResultData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					if entry, ok := pending[data.ID]; ok {
						entry.Output = data.Output
						entry.Error = data.Error
						entry.Duration = int(data.DurationMS)
						toolCalls = append(toolCalls, *entry)
						delete(pending, data.ID)
					}
				}
			case serviceEventFinal:
				var data serviceFinalData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					final = &data
				}
			}
		}
	}
}

func resetNoopCompactionTimer(timer *time.Timer, limit time.Duration) (*time.Timer, <-chan time.Time) {
	if limit <= 0 {
		return timer, nil
	}
	if timer == nil {
		timer = time.NewTimer(limit)
		return timer, timer.C
	}
	stopNoopCompactionTimer(timer)
	timer.Reset(limit)
	return timer, timer.C
}

func stopNoopCompactionTimer(timer *time.Timer) {
	if timer == nil {
		return
	}
	if !timer.Stop() {
		select {
		case <-timer.C:
		default:
		}
	}
}

type serviceNoopCompactionStreak struct {
	start time.Time
	count int
}

func (s *serviceNoopCompactionStreak) record(ts time.Time, limit time.Duration) (string, bool) {
	if limit <= 0 {
		return "", false
	}
	if ts.IsZero() {
		ts = time.Now().UTC()
	}
	started := false
	if s.count == 0 {
		s.start = ts
		started = true
	}
	s.count++
	elapsed := ts.Sub(s.start)
	if elapsed < limit {
		return "", started
	}
	return s.detail(elapsed, limit), started
}

func (s *serviceNoopCompactionStreak) detail(elapsed, limit time.Duration) string {
	if elapsed < limit {
		elapsed = limit
	}
	return fmt.Sprintf("%s: time-based breaker fired after %s of consecutive no-op compaction events (limit %s, count %d)",
		serviceNoopCompactionWallClockReason,
		elapsed.Round(time.Second),
		limit.Round(time.Second),
		s.count)
}

func (s *serviceNoopCompactionStreak) reset() {
	s.start = time.Time{}
	s.count = 0
}

func eventTimestamp(ev agentlib.ServiceEvent) time.Time {
	if !ev.Time.IsZero() {
		return ev.Time
	}
	return time.Now().UTC()
}

func isNoopCompactionEvent(ev agentlib.ServiceEvent) bool {
	switch string(ev.Type) {
	case serviceEventCompaction, serviceEventCompactionEnd:
	default:
		return false
	}
	var payload struct {
		NoCompaction bool `json:"no_compaction"`
	}
	if err := json.Unmarshal(ev.Data, &payload); err != nil {
		return false
	}
	return payload.NoCompaction
}

func isServiceProgressEvent(ev agentlib.ServiceEvent) bool {
	switch string(ev.Type) {
	case serviceEventProgress, serviceEventTextDelta, serviceEventToolCall, serviceEventToolResult, serviceEventCompaction, serviceEventCompactionEnd:
		return true
	default:
		return false
	}
}

func toolCallsWithPending(toolCalls []ToolCallEntry, pending map[string]*ToolCallEntry) []ToolCallEntry {
	for _, entry := range pending {
		toolCalls = append(toolCalls, *entry)
	}
	return toolCalls
}

package fizeau

import (
	"context"
	"encoding/json"
	"strings"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/fizeau/internal/harnesses"
)

type subprocessProgressHarness struct {
	events []harnesses.Event
}

func (h *subprocessProgressHarness) Info() harnesses.HarnessInfo {
	return harnesses.HarnessInfo{Name: "codex", Type: "subprocess", Available: true}
}

func (h *subprocessProgressHarness) HealthCheck(context.Context) error { return nil }

func (h *subprocessProgressHarness) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
	out := make(chan harnesses.Event, len(h.events))
	go func() {
		defer close(out)
		for _, ev := range h.events {
			select {
			case out <- ev:
			case <-ctx.Done():
				return
			}
		}
	}()
	return out, nil
}

func TestRunSubprocess_EmitsToolProgress(t *testing.T) {
	events := runSubprocessProgressEvents(t, []harnesses.Event{
		harnessEvent(t, harnesses.EventTypeToolCall, harnesses.ToolCallData{ID: "tool-1", Name: "bash", Input: json.RawMessage(`{"command":"echo hi"}`)}),
		harnessEvent(t, harnesses.EventTypeToolResult, harnesses.ToolResultData{ID: "tool-1", Output: "tool output", DurationMS: 7}),
		harnessEvent(t, harnesses.EventTypeFinal, harnesses.FinalData{Status: "success"}),
	})

	var sawStart, sawComplete bool
	for _, p := range subprocessProgressEvents(events) {
		if p.Phase != "tool" {
			continue
		}
		switch p.State {
		case "start":
			sawStart = true
			if p.ToolName != "bash" || !strings.Contains(p.Command, "echo hi") {
				t.Fatalf("tool start progress = %#v", p)
			}
		case "complete":
			sawComplete = true
			if p.ToolName != "bash" || p.DurationMS != 7 {
				t.Fatalf("tool complete progress = %#v", p)
			}
		}
	}
	if !sawStart || !sawComplete {
		t.Fatalf("missing tool progress events: %#v", subprocessProgressEvents(events))
	}
}

func TestRunSubprocess_EmitsResponseProgress(t *testing.T) {
	events := runSubprocessProgressEvents(t, []harnesses.Event{
		harnessEvent(t, harnesses.EventTypeFinal, harnesses.FinalData{
			Status:     "success",
			DurationMS: 42,
			Usage: &harnesses.FinalUsage{
				InputTokens:  harnesses.IntPtr(10),
				OutputTokens: harnesses.IntPtr(5),
				TotalTokens:  harnesses.IntPtr(15),
			},
		}),
	})

	for _, p := range subprocessProgressEvents(events) {
		if p.Phase == "response" && p.State == "complete" {
			if p.DurationMS != 42 || p.TotalTokens == nil || *p.TotalTokens != 15 {
				t.Fatalf("response progress = %#v", p)
			}
			return
		}
	}
	t.Fatalf("missing response progress: %#v", subprocessProgressEvents(events))
}

func TestSubprocessProgress_DoesNotDuplicateFinalOrToolEvents(t *testing.T) {
	events := runSubprocessProgressEvents(t, []harnesses.Event{
		harnessEvent(t, harnesses.EventTypeToolCall, harnesses.ToolCallData{ID: "tool-1", Name: "bash", Input: json.RawMessage(`{"command":"echo hi"}`)}),
		harnessEvent(t, harnesses.EventTypeToolResult, harnesses.ToolResultData{ID: "tool-1", Output: "tool output", DurationMS: 7}),
		harnessEvent(t, harnesses.EventTypeFinal, harnesses.FinalData{Status: "success"}),
	})

	counts := map[harnesses.EventType]int{}
	for _, ev := range events {
		counts[ev.Type]++
	}
	if counts[harnesses.EventTypeToolCall] != 1 || counts[harnesses.EventTypeToolResult] != 1 || counts[harnesses.EventTypeFinal] != 1 {
		t.Fatalf("event counts = %#v, want one original tool_call/tool_result/final", counts)
	}
}

func TestSubprocessProgress_BoundsSessionLogSummaries(t *testing.T) {
	prompt := strings.Repeat("PROMPT-SECRET-", 30)
	output := strings.Repeat("TOOL-SECRET-", 40)
	events := runSubprocessProgressEvents(t, []harnesses.Event{
		harnessEvent(t, harnesses.EventTypeToolCall, harnesses.ToolCallData{ID: "tool-1", Name: "bash", Input: json.RawMessage(`{"command":"echo hi"}`)}),
		harnessEvent(t, harnesses.EventTypeToolResult, harnesses.ToolResultData{ID: "tool-1", Output: output, DurationMS: 7}),
		harnessEvent(t, harnesses.EventTypeFinal, harnesses.FinalData{Status: "success", FinalText: "done"}),
	}, func(req *ServiceExecuteRequest) {
		req.Prompt = prompt
	})

	for _, p := range subprocessProgressEvents(events) {
		raw, err := json.Marshal(p)
		if err != nil {
			t.Fatalf("marshal progress: %v", err)
		}
		if len(p.SessionSummary) > 240 {
			t.Fatalf("session summary too long: %d", len(p.SessionSummary))
		}
		if strings.Contains(string(raw), prompt) || strings.Contains(string(raw), output) {
			t.Fatalf("progress leaked prompt or tool output: %s", raw)
		}
	}
}

func runSubprocessProgressEvents(t *testing.T, harnessEvents []harnesses.Event, mutateReq ...func(*ServiceExecuteRequest)) []ServiceEvent {
	t.Helper()
	req := ServiceExecuteRequest{
		Prompt:        "subprocess prompt",
		SessionLogDir: t.TempDir(),
	}
	for _, mutate := range mutateReq {
		mutate(&req)
	}
	decision := RouteDecision{Harness: "codex", Provider: "codex", Model: "gpt-test"}
	svc := &service{}
	sl := svc.openSessionLog(req, decision, "subprocess-progress-session")
	defer sl.close()

	out := make(chan ServiceEvent, 16)
	var seq atomic.Int64
	svc.runSubprocess(context.Background(), req, decision, nil, out, &seq, time.Now(), sl, "subprocess-progress-session", &subprocessProgressHarness{events: harnessEvents})
	close(out)

	var events []ServiceEvent
	for ev := range out {
		events = append(events, ev)
	}
	return events
}

func subprocessProgressEvents(events []ServiceEvent) []ServiceProgressData {
	var out []ServiceProgressData
	for _, ev := range events {
		if ev.Type != harnesses.EventTypeProgress {
			continue
		}
		var payload ServiceProgressData
		_ = json.Unmarshal(ev.Data, &payload)
		out = append(out, payload)
	}
	return out
}

func harnessEvent(t *testing.T, typ harnesses.EventType, payload any) harnesses.Event {
	t.Helper()
	raw, err := json.Marshal(payload)
	if err != nil {
		t.Fatalf("marshal harness event: %v", err)
	}
	return harnesses.Event{
		Type: typ,
		Time: time.Now().UTC(),
		Data: raw,
	}
}

package fizeau

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"time"
)

const (
	ServiceEventTypeTextDelta        = "text_delta"
	ServiceEventTypeToolCall         = "tool_call"
	ServiceEventTypeToolResult       = "tool_result"
	ServiceEventTypeCompaction       = "compaction"
